3_real_world_example.code:
const userState = {
  id: 42,
  name: 'Alice',
  isOnline: false
};

// We need to update isOnline to true, but we CANNOT mutate the original.
// We create a NEW object, spread the old properties into it, 
// and overwrite the specific property we want to change.
const updatedState = {
  ...userState,
  isOnline: true // Overwrites the false value from userState
};

console.log(userState.isOnline);  // false (Original untouched)
console.log(updatedState.isOnline); // true (New object updated)

